package com.example.demo;

import org.springframework.web.bind.annotation.*;
import org.springframework.web.client.RestTemplate;
import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;

@RestController
public class WebhookController {

    private final RestTemplate restTemplate = new RestTemplate();

    @PostMapping("/webhook")
    public String handleWebhook(@RequestBody WebhookRequest request) {
        try {
            String content = fetchContent(request.getUrl());
            return content;
        } catch (Exception e) {
            return "Error fetching content: " + e.getMessage();
        }
    }

    private String fetchContent(String url) throws Exception {
        HttpClient client = HttpClient.newHttpClient();
        HttpRequest request = HttpRequest.newBuilder()
                .uri(URI.create(url))
                .build();

        HttpResponse<String> response = client.send(request, HttpResponse.BodyHandlers.ofString());
        return response.body();
    }
}

class WebhookRequest {
    private String url;

    // Getters and Setters
    public String getUrl() {
        return url;
    }

    public void setUrl(String url) {
        this.url = url;
    }
}